// Parse the JSON output from Claude into individual fields
const raw = $input.item.json.message?.content?.[0]?.text || $input.item.json.text || '';
let parsed;
try {
  const clean = raw.replace(/```json|```/g, '').trim();
  parsed = JSON.parse(clean);
} catch(e) {
  throw new Error("Failed to parse email JSON from AI: " + raw.substring(0, 200));
}

return {
  json: {
    ...$input.item.json,
    "Email#1 Subject": parsed["Email#1 Subject"] || '',
    "Email#1 Body":    parsed["Email#1 Body"] || '',
    "Email#2 Subject": parsed["Email#2 Subject"] || '',
    "Email#2 Body":    parsed["Email#2 Body"] || '',
    "Email#3 Subject": parsed["Email#3 Subject"] || '',
    "Email#3 Body":    parsed["Email#3 Body"] || ''
  }
};

const country = (item.json["Country "] || "").toLowerCase().trim();
const t1 = ["usa","united states","canada"];
const t2 = ["albania","andorra","armenia","austria","azerbaijan","belarus","belgium","bosnia and herzegovina","bulgaria","croatia","cyprus","czech republic","czechia","denmark","estonia","finland","france","georgia","germany","greece","hungary","iceland","ireland","italy","kosovo","latvia","liechtenstein","lithuania","luxembourg","malta","moldova","monaco","montenegro","netherlands","north macedonia","norway","poland","portugal","romania","russia","san marino","serbia","slovakia","slovenia","spain","sweden","switzerland","turkey","ukraine","united kingdom","united kingdom (uk)","uk","great britain","vatican city"];
const t3 = ["australia","new zealand"];

if (t1.includes(country))       item.json["Time Zone"] = "T1";
else if (t2.includes(country))  item.json["Time Zone"] = "T2";
else if (t3.includes(country))  item.json["Time Zone"] = "T3";
else                             item.json["Time Zone"] = "T4";
return item;

const senders = ["sender1@yourdomain.com", "sender2@yourdomain.com", "sender3@gmail.com"];
const idx = $itemIndex % senders.length;
$input.item.json["Sender Email"] = senders[idx];
return $input.item;

const token = ([1e7]+-1e3+-4e3+-8e3+-1e11).replace(/[018]/g, c =>
  (c ^ (typeof crypto !== 'undefined' ? crypto.getRandomValues(new Uint8Array(1))[0] : Math.random() * 256 | 0) & 15 >> c / 4).toString(16));
$input.item.json["Token"] = token;
return $input.item;

// Build RFC-2822 in-thread HTML reply for Gmail API
const emailNum = 2; // 2 or 3
const emailData = {
  messageId: $input.item.json['Message ID'],
  threadId:  $input.item.json['Thread ID'] || $input.item.json['Message ID'],
  subject:   $input.item.json['Email#1 Subject'],
  sender:    $input.item.json['Sender Email'],
  recipient: $input.item.json['Email Address'],
  token:     $input.item.json['Token']
};

// Resolve email body with fallback chain
const bodyKey   = `Email#${emailNum} Body`;
const bodyValue = $input.item.json[bodyKey] || $input.item.json[`Email #${emailNum} Body`] || '';
if (!bodyValue) throw new Error(`Missing ${bodyKey} — check Research Agent output`);

const msgId   = emailData.messageId.startsWith('<') ? emailData.messageId : `<${emailData.messageId}>`;
const htmlBody = `${bodyValue}<br><br><a href="${https://YOUR-N8N-INSTANCE.app.n8n.cloud}/webhook/unsubscribe?tkn=${emailData.token}">Click here to unsubscribe</a>`;

const raw = [
  `In-Reply-To: ${msgId}`,
  `References: ${msgId}`,
  `Subject: Re: ${emailData.subject}`,
  `From: ${emailData.sender}`,
  `To: ${emailData.recipient}`,
  `Content-Type: text/html; charset="UTF-8"`,
  ``,
  htmlBody
].join('\r\n');

const encoded = Buffer.from(raw).toString('base64').replace(/\+/g,'-').replace(/\//g,'_').replace(/=+$/,'');
return { json: { raw: encoded, threadId: emailData.threadId } };

